// DAP admin rejection email copy.
// Copy is soft, neutral, and non-accusatory.
// CB Control Center makes enrollment decisions. MKCRM does not. Payment systems do not.
// Preview-only. No email sending. No PHI. No payment CTAs. No insurance-like language.

import type {
  DapAdminRejectionEmailTemplateKey,
  DapAdminRejectionEmailCopy,
} from './dapAdminRejectionEmailTypes'

// ─── Required footer note (locked language) ────────────────────────────────────

export const DAP_REJECTION_FOOTER_NOTE =
  'This is a preview of an administrative notification generated by CB Control Center. ' +
  'No email has been sent. MKCRM does not decide rejections. ' +
  'Client Builder Pro and payment systems have no authority over DAP enrollment decisions.'

// ─── Forbidden copy terms ─────────────────────────────────────────────────────

export const DAP_REJECTION_FORBIDDEN_TERMS: string[] = [
  'denied',
  'failed',
  'blacklisted',
  'fraud',
  'terminated',
  'charged',
  'payment required',
  'claim',
  'insurance',
  'coverage',
  'benefits',
  'hipaa',
  'diagnosis',
  'procedure',
  'treatment',
  'pay now',
  'update payment',
  'checkout',
  'billing portal',
  'mkcrm determines',
  'mkcrm has authority',
  'mkcrm decides',
  'patient health',
  'medical record',
  'date of birth',
  'social security',
]

