// ─── Accessors ────────────────────────────────────────────────────────────────

export function getDapAdminRejectionEmailCopy(
  templateKey: DapAdminRejectionEmailTemplateKey
): DapAdminRejectionEmailCopy {
  return REJECTION_COPY[templateKey]
}

export function getAllDapAdminRejectionEmailCopy(): DapAdminRejectionEmailCopy[] {
  return Object.values(REJECTION_COPY)
}

// ─── Safety scanner ───────────────────────────────────────────────────────────

function collectCopyText(copy: DapAdminRejectionEmailCopy): string {
  return [copy.subject, copy.headline, copy.previewText, ...copy.body, copy.footerNote]
    .join(' ')
    .toLowerCase()
}

export function isDapAdminRejectionEmailCopySafe(copy: DapAdminRejectionEmailCopy): boolean {
  if (copy.includesPaymentCta !== false) return false
  if (copy.includesPhi !== false) return false
  if (copy.includesCta !== false) return false
  const text = collectCopyText(copy)
  return !DAP_REJECTION_FORBIDDEN_TERMS.some(term => text.includes(term.toLowerCase()))
}

export function assertDapAdminRejectionEmailCopySafe(copy: DapAdminRejectionEmailCopy): void {
  if (copy.includesPaymentCta !== false) {
    throw new Error('Rejection email copy must have includesPaymentCta: false.')
  }
  if (copy.includesPhi !== false) {
    throw new Error('Rejection email copy must have includesPhi: false.')
  }
  if (copy.includesCta !== false) {
    throw new Error('Rejection email copy must have includesCta: false.')
  }
  const text = collectCopyText(copy)
  for (const term of DAP_REJECTION_FORBIDDEN_TERMS) {
    if (text.includes(term.toLowerCase())) {
      throw new Error(`Rejection email copy contains forbidden term: "${term}".`)
    }
  }
}
